To prevent SQL Injection in the code snippet you provided, you should use parameterized queries instead of concatenating user input directly into the SQL query string. Parameterized queries help to separate the SQL code from user input, making it more secure.

Here's how you can modify the code to use a parameterized query:

```java
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class SQLInjectionFixed {
    public static void main(String[] args) {
        String userInput = args[0]; // Simulating user input directly assigned to a variable

        try {
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            String query = "SELECT * FROM users WHERE username=?";
            PreparedStatement pstmt = conn.prepareStatement(query);
            pstmt.setString(1, userInput); // Set the parameter value

            ResultSet rs = pstmt.executeQuery();

            while (rs.next()) {
                System.out.println("User ID: " + rs.getInt("id") + ", Username: " + rs.getString("username"));
            }

            conn.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}
``

